// // Concatenates two 16-bit input signals, in_a and in_b, to produce a single 32-bit output. The output is formed by placing in_b as the higher 16 bits and in_a as the lower 16 bits of the 32-bit result.
module top_module(
  in_a,
  in_b,
  out
);input wire [15:0] in_a;
input wire [15:0] in_b;
output wire [31:0] out;

assign out = {in_a, in_b};

endmodule
